#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
typedef long long LL;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int Mod=19260817;const LL INF=0x3f3f3f3f3f3f3f3fll;
int n;LL a,b;LL dp[Mod];int nxt[Mod],stk[100010],top;
struct Hsh
{
	int idx[Mod];inline int operator [] (const int &x)
	{
		int hsh=x%Mod;while(idx[hsh]!=x&&idx[hsh])(++hsh)==Mod?hsh=0:0;
		idx[hsh]=x;return hsh;
	}
}idx;
inline LL dfs(const int &x)
{
	int p=idx[x];if(dp[p]<INF)return dp[p];
	for(int l=1,r=0;l<x;l=r+1)
	{
		r=(x-1)/((x-1)/l);LL cur=dfs(l)+(((x-1)/l)+1)*b+x*a;
		if(cur<dp[p]){dp[p]=cur;nxt[p]=l;}
	}
	return dp[p];
}
int main()
{
	n=read();a=read();b=read();
	memset(dp,0x3f,sizeof(dp));dp[idx[1]]=0;dfs(n);
	int t=n;while(t!=1){t=nxt[idx[t]];stk[++top]=t;}
	printf("%lld %d\n",dp[idx[n]],top);
	rep(1,top,i)printf("%d ",stk[i]);
}
